import React, { useState, useEffect } from "react";
import FAWCheckbox from "../../../../../component-widget/FAWCheckbox";
import EditorSection from "./EditorSection";

export default function FAWCloningOptions({ 
  data = {}, 
  onChange,
  neverClone = false,
  isDeployed = false
}) {
  const [localData, setLocalData] = useState({
    neverClone: neverClone
  });

  useEffect(() => {
    setLocalData({
      neverClone: data.neverClone ?? false
    });
  }, [data.neverClone]);

  const handleChange = (field, value) => {
    const newData = { ...localData, [field]: value };
    setLocalData(newData);
    onChange?.(newData);
  };

  return (
    <EditorSection title="Cloning Options">
      <div style={{ display: "flex", alignItems: "center", gap: 16 }}>
        <FAWCheckbox
          label="Never Clone"
          checked={localData.neverClone}
          onChange={(e) => handleChange("neverClone", e.target.checked)}
          disabled={isDeployed}
        />
      </div>
    </EditorSection>
  );
}
