import React, { useEffect, useState } from "react";
import axios from "axios";
import FAWInput from "../../../../component-widget/FAWInput";
import FAWDropdown from "../../../../component-widget/FAWDropdown";
import FAWCheckbox from "../../../../component-widget/FAWCheckbox";
import FAWButton from "../../../../component-widget/FAWButton";
import FAWToast from "../../../../component-widget/FAWToast";
import FAWItemOptionsEditor from "./shared/FAWItemOptionsEditor";
import EditorShell from "./shared/EditorShell";
import BaseQuestionFields from "./shared/BaseQuestionFields";
import EditorSection from "./shared/EditorSection";
import FAWFlagSettings from "./shared/FAWFlagSettings";
import FAWAddPrefill from "./shared/FAWAddPrefill";
import FAWCloningOptions from "./shared/FAWCloningOptions";

export default function QueRadioButtonItemEditor({ 
  data, 
  onSave, 
  onClose, 
  saveRef, 
  isDefaultLanguage = true,
  availableDroplists = [],
  availableFormFields = [],
  availableRefDomains = [],
  domains = [],
  isDeployed = false
}) {
  const [item, setItem] = useState(
    data || {
      name: "",
      text: "",
      required: false,
      validationMessage: "",
      horizontalLine: false,
      layout: "Vertical",
      readOnly: false,
      options: [],
      optionsRefDomain: "",
      flagSettings: {},
      cloningOptions: {},
      prefillSettings: {},
    }
  );
  const [toast, setToast] = useState({ open: false, message: '', type: 'info', duration: 3000 });
  // Add isSubForm state
  const [isSubForm, setIsSubForm] = useState(data?.isSubForm || false);

  useEffect(() => { if (data) setItem(prev => ({ ...prev, ...data })); }, [data]);

  const handleChange = (field, value) => setItem(prev => ({ ...prev, [field]: value }));
  
  // Handle options payload changes from AtlasItemOptionsEditor
  const handleOptionsChange = (payload) => {
    setItem(prev => ({
      ...prev,
      optionsPayload: payload,
      // Also update the legacy fields for backward compatibility
      optionsRefDomain: payload.optionsRefDomain || prev.optionsRefDomain,
      options: payload.options || prev.options,
    }));
  };
  const handleSave = () => {
    // Prevent save if version is deployed
    if (isDeployed) {
      setToast({ open: true, message: "You cannot save this item since it is a part of a currently active version", type: 'error', duration: 5000 });
      return;
    } 
    onSave?.(item); 
  };

  const handleUpdatePossibleAnswers = async () => {
    try {
      const currentPayload = item.optionsPayload;
      
      if (!currentPayload) {
        setToast({ open: true, message: 'Please configure options first.', type: 'warning', duration: 3000 });
        return;
      }

      if (currentPayload.mode === "RefCode" || currentPayload.mode === "Dependency") {
        // For RefCode and Dependency modes, refresh from selected domain
        // Dependency mode also uses RefCode domain values, similar to legacy behavior
        const domain = currentPayload.mode === "Dependency" 
          ? currentPayload.dependency?.dependencyDomain 
          : currentPayload.optionsRefDomain;
        
        if (!domain) {
          const message = currentPayload.mode === "Dependency"
            ? 'Please select a Dependency and a Domain first.'
            : 'Please select a Reference Domain first.';
          setToast({ open: true, message, type: 'warning', duration: 3000 });
          return;
        }
        
        // For Dependency mode, also validate parent droplist is selected
        if (currentPayload.mode === "Dependency" && !currentPayload.dependency?.parentDroplist) {
          setToast({ open: true, message: 'Please select a parent Droplist first.', type: 'warning', duration: 3000 });
          return;
        }
        
        // Fetch fresh options from domain
        const response = await axios.get('/RefCode/GetRefCodesOfDomain', {
          params: { domainCode: domain }
        });
        
        const updatedOptions = response.data.map(rc => ({
          optionText: rc.Meaning,
          optionValue: rc.Code,
          conflict: false
        }));
        
        // Preserve existing flag settings and subform properties
        const existingFlags = item.flagSettings?.flagsAdded || [];
        const existingSubForms = item.subFormSettings?.addedSubForms || [];
        
        // Update flag settings based on new options
        const newFlagSettings = {
          ...item.flagSettings,
          flagsToAdd: updatedOptions.filter(opt => 
            !existingFlags.some(flag => flag.optionValue === opt.optionValue)
          ),
          flagsAdded: existingFlags.filter(flag => 
            updatedOptions.some(opt => opt.optionValue === flag.optionValue)
          )
        };
        
        // Update subform settings based on new options
        const newSubFormSettings = {
          ...item.subFormSettings,
          subFormsToAdd: updatedOptions.filter(opt => 
            !existingSubForms.some(sf => sf.optionValue === opt.optionValue)
          ),
          addedSubForms: existingSubForms.filter(sf => 
            updatedOptions.some(opt => opt.optionValue === sf.optionValue)
          )
        };
        
        // Update the complete item state
        setItem(prev => ({ 
          ...prev, 
          options: updatedOptions,
          optionsPayload: {
            ...prev.optionsPayload,
            options: updatedOptions
          },
          flagSettings: newFlagSettings,
          subFormSettings: newSubFormSettings
        }));
        
        setToast({ 
          open: true, 
          message: `Updated ${updatedOptions.length} possible answers from domain: ${domain}. Existing flag and subform settings preserved.`, 
          type: 'success', 
          duration: 5000 
        });
      } else if (currentPayload.mode === "StaticList") {
        // For StaticList mode, validate and process current options
        const options = currentPayload?.options || [];
        const validOptions = options.filter(opt => 
          opt.optionText && opt.optionText.trim() !== "" && 
          opt.optionValue && opt.optionValue.trim() !== ""
        );
        
        // Preserve existing flag and subform settings for valid options
        const existingFlags = item.flagSettings?.flagsAdded || [];
        const existingSubForms = item.subFormSettings?.addedSubForms || [];
        
        const newFlagSettings = {
          ...item.flagSettings,
          flagsToAdd: validOptions.filter(opt => 
            !existingFlags.some(flag => flag.optionValue === opt.optionValue)
          ),
          flagsAdded: existingFlags.filter(flag => 
            validOptions.some(opt => opt.optionValue === flag.optionValue)
          )
        };
        
        const newSubFormSettings = {
          ...item.subFormSettings,
          subFormsToAdd: validOptions.filter(opt => 
            !existingSubForms.some(sf => sf.optionValue === opt.optionValue)
          ),
          addedSubForms: existingSubForms.filter(sf => 
            validOptions.some(opt => opt.optionValue === sf.optionValue)
          )
        };
        
        setItem(prev => ({
          ...prev,
          flagSettings: newFlagSettings,
          subFormSettings: newSubFormSettings
        }));
        
        setToast({ 
          open: true, 
          message: `Processed ${validOptions.length} valid options. Empty options were ignored. Flag and subform settings updated.`, 
          type: 'success', 
          duration: 5000 
        });
      } else {
        setToast({ 
          open: true, 
          message: 'Update Possible Answers is only available for RefCode, Dependency, and StaticList modes.', 
          type: 'warning', 
          duration: 3000 
        });
      }
    } catch (error) {
      console.error('Failed to update possible answers:', error);
      setToast({ 
        open: true, 
        message: 'Failed to update possible answers. Please try again.', 
        type: 'error', 
        duration: 5000 
      });
    }
  };

  return (
    <EditorShell onSave={handleSave} onClose={onClose} saveRef={saveRef}>
      <BaseQuestionFields item={item} onChange={setItem} isDefaultLanguage={isDefaultLanguage} isDeployed={isDeployed} questionType="RadioButtonListItemType" />
      
      <EditorSection title="">
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
          <FAWDropdown 
            label="Layout" 
            value={item.layout} 
            onChange={(opt)=>handleChange('layout', opt.value)} 
            options={[
              {label:'Vertical', value:'Vertical'},
              {label:'Horizontal', value:'Horizontal'}
            ]} 
            fullWidth
          />
          <div style={{ display: 'flex', alignItems: 'center', marginTop: 24 }}>
            <FAWCheckbox 
              label="Read Only" 
              checked={item.readOnly} 
              onChange={(e)=>handleChange('readOnly', e.target.checked)} 
            />
          </div>
        </div>
      </EditorSection>
      
      <EditorSection title="Options Editor">
        <FAWItemOptionsEditor 
          options={item.options} 
          optionsRefDomain={item.optionsRefDomain} 
          defaultMode={item.mode || (item.optionsPayload?.mode)}
          allowConflictFlag={true} 
          allowedModes={["RefCode", "StaticList", "Dependency", "FormField"]}
          availableDroplists={availableDroplists}
          availableFormFields={availableFormFields}
          availableRefDomains={availableRefDomains}
          domains={domains}
          isCustomField={item._source?.rc?.Domain === "CustomFields"}
          dependency={item.dependency || item.optionsPayload?.dependency}
          onChange={handleOptionsChange} 
          isExistingQuestion={!!(data?.id || data?.Id)}
          isDeployed={isDeployed}
        />
        <div style={{ marginTop: 16 }}>
          <FAWButton variant="contained" onClick={handleUpdatePossibleAnswers}>
            Update Possible Answers
          </FAWButton>
        </div>
      </EditorSection>
      
      {/* Show Flag Settings when YesNo domain is selected and options have been loaded */}
      {item.optionsPayload?.optionsRefDomain === "YesNo" && item.options && item.options.length > 0 && (
        <FAWFlagSettings 
          data={item.flagSettings} 
          onChange={(data) => handleChange("flagSettings", data)}
          availableFlags={(item.options || []).map(option => ({
            label: option.optionText || option.text || String(option),
            value: option.optionValue || option.value || String(option),
            text: option.optionText || option.text || String(option),
            FlagAsConflict: option.FlagAsConflict || option.conflict || false
          }))}
          isDeployed={isDeployed}
        />
      )}
      
      
             <FAWCloningOptions 
         data={item.cloningOptions} 
         onChange={(data) => handleChange("cloningOptions", data)}
       />
       
       <FAWToast 
         open={toast.open} 
         message={toast.message} 
         type={toast.type} 
         duration={toast.duration}
         onClose={() => setToast({ open: false, message: '', type: 'info' })} 
       />
     </EditorShell>
   );
 }